messages.content:
Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "required": [
    "transactions"
  ],
  "properties": {
    "transactions": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "period",
          "value",
          "category"
        ],
        "properties": {
          "value": {
            "type": "number",
            "description": "The value of the transaction in millions."
          },
          "period": {
            "type": "string",
            "pattern": "^Q[1-4]-\\d{4}$",
            "description": "The period in the format Q[1-4]-YYYY (e.g., Q1-2017)."
          },
          "category": {
            "type": "string",
            "description": "The category of the transaction (e.g., Multifamily Housing)."
          }
        },
        "additionalProperties": false
      },
      "description": "Quarterly real estate transcations by property class."
    },
    "transactionsByCity": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "year",
          "value",
          "city"
        ],
        "properties": {
          "city": {
            "type": "string",
            "description": "City name"
          },
          "year": {
            "type": "string",
            "description": "The year in YYYY format (e.g. 2017)."
          },
          "value": {
            "type": "number",
            "description": "Total value transactions in millions."
          }
        },
        "additionalProperties": false
      },
      "description": "Total Real estate transcations by city."
    }
  },
  "additionalProperties": false
}
